import styled from "styled-components";
import Column from "smart-react-components/grid/Column";
import CodeIcon from "./icons/Code";
export default styled(Column).attrs(({ single, px = 0, pxMd = "cardPadding", pb = 3, pbMd = 0 }) => ({
    col: 12,
    colMd: single ? 12 : 6,
    px,
    pxMd,
    pb,
    pbMd
}))(({ theme }) => `
    &:first-child {
        padding-left: 0 !important;
    }

    &:last-child {
        padding-right: 0 !important;
        padding-bottom: 0 !important;
    }
    
    > div {
        height: 100%;
        padding: 25px 10px;
        border: solid 1px ${theme.src.color.gray_300};
        border-radius: ${theme.src.radius.card};

        ${CodeIcon} {
            width: 1rem;
            height: 1rem;
            fill: ${theme.src.color.gray_300};
        }

        > section {
            padding-top: 25px;
        }
    }
`);
